<span class="line"><span style="color:#F9E2AF;">            Constraint</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">Percentage</span><span style="color:#9399B2;">(</span><span style="color:#FAB387;">50</span><span style="color:#9399B2;">),</span></span>
